# shapes.spy - Base abstractions for geometric shapes
enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3
    YELLOW = 4

interface IDrawable:
    def draw(self) -> str: ...

@abstract
class Shape:
    color: Color

    @abstract
    def area(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return "A shape"

