# geometry.spy - Concrete shape implementations
from shapes import Color, Shape, IDrawable

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

class Rectangle(Shape, IDrawable):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color):
        self.width = width
        self.height = height
        self.color = color

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def draw(self) -> str:
        return "Drawing Rectangle"

    @override
    def describe(self) -> str:
        return f"Rectangle {self.width}x{self.height}"

class Circle(Shape, IDrawable):
    radius: float

    def __init__(self, radius: float, color: Color):
        self.radius = radius
        self.color = color

    @override
    def area(self) -> float:
        return 3.14 * self.radius * self.radius

    @override
    def draw(self) -> str:
        return "Drawing Circle"

    @override
    def describe(self) -> str:
        return f"Circle radius={self.radius}"

