# utils.spy - Utility functions for shape operations
from shapes import Shape, Color
from geometry import Point

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.area()
    return total

def create_origin() -> Point:
    return Point(0.0, 0.0)
